import { createSlice, createAsyncThunk, PayloadAction } from '@reduxjs/toolkit'
import { collection, query, getDocs } from 'firebase/firestore'
import { db } from '@/lib/firebase'

export interface HomeCard {
  id: string
  title: string
  description: string
  link: string
}

interface HomeState {
  homeCards: HomeCard[]
  loading: boolean
  error: string | null
}

const initialState: HomeState = {
  homeCards: [],
  loading: false,
  error: null
}

export const fetchHomeCards = createAsyncThunk(
  'home/fetchHomeCards',
  async () => {
    const q = query(collection(db, "HomeCard"))
    const querySnapshot = await getDocs(q)
    const cards: HomeCard[] = []
    querySnapshot.forEach((doc) => {
      const data = doc.data()
      cards.push({
        id: doc.id,
        title: data.title || "Untitled",
        description: data.description || "No description",
        link: data.link || "/",
      })
    })
    return cards
  }
)

const homeSlice = createSlice({
  name: 'home',
  initialState,
  reducers: {
    clearHomeError: (state) => {
      state.error = null
    }
  },
  extraReducers: (builder) => {
    builder
      .addCase(fetchHomeCards.pending, (state) => {
        state.loading = true
        state.error = null
      })
      .addCase(fetchHomeCards.fulfilled, (state, action: PayloadAction<HomeCard[]>) => {
        state.loading = false
        state.homeCards = action.payload
      })
      .addCase(fetchHomeCards.rejected, (state, action) => {
        state.loading = false
        state.error = action.error.message || 'Failed to fetch home cards'
      })
  }
})

export const { clearHomeError } = homeSlice.actions
export default homeSlice.reducer